"""Comprehensive QA: Test all acceptance criteria for BRUTALWAV DAW."""
from playwright.sync_api import sync_playwright
import json

FINDINGS = []

def finding(severity, category, msg, detail=""):
    FINDINGS.append({"severity": severity, "category": category, "message": msg, "detail": detail})
    print(f"[{severity}] {category}: {msg}")
    if detail:
        print(f"    Detail: {detail}")

with sync_playwright() as p:
    browser = p.chromium.launch(headless=True)
    context = browser.new_context(viewport={"width": 1280, "height": 800})
    page = context.new_page()

    console_errors = []
    page.on("console", lambda msg: console_errors.append(msg.text) if msg.type == "error" else None)
    page_errors = []
    page.on("pageerror", lambda err: page_errors.append(str(err)))

    # === SETUP: Navigate and start audio engine ===
    page.goto("http://localhost:5173/", wait_until="networkidle")
    page.click("button")
    page.wait_for_timeout(2000)

    if page_errors:
        for e in page_errors:
            finding("P0", "StartupError", "Page error during startup", e)
    else:
        finding("PASS", "Startup", "App starts without page errors")

    if console_errors:
        for e in console_errors:
            finding("P1", "ConsoleError", "Console error during startup", e)
    else:
        finding("PASS", "Console", "No console errors during startup")

    # === TEST 1: All major panels render ===
    print("\n=== TEST 1: Panel Rendering ===")

    # Toolbar
    toolbar = page.locator("text=BRUTALWAV").first
    if toolbar.is_visible():
        finding("PASS", "Panels", "Toolbar/logo visible")
    else:
        finding("P1", "Panels", "Toolbar/logo NOT visible")

    # Transport area (BPM, play/stop, etc.)
    bpm_input = page.locator("input").first
    if bpm_input.is_visible():
        bpm_val = bpm_input.input_value()
        finding("PASS", "Panels", f"BPM input visible (value: {bpm_val})")
    else:
        finding("P1", "Panels", "BPM input NOT found")

    # Arrangement area
    arrangement_text = page.locator("text=No tracks yet")
    if arrangement_text.count() > 0 and arrangement_text.first.is_visible():
        finding("PASS", "Panels", "Arrangement area visible (empty state)")
    else:
        finding("P2", "Panels", "Arrangement empty state text not found")

    # Mixer - Master channel
    master = page.locator("text=MASTER")
    if master.count() > 0 and master.first.is_visible():
        finding("PASS", "Panels", "Mixer panel visible with MASTER channel")
    else:
        finding("P1", "Panels", "Mixer/MASTER channel NOT visible")

    # Instrument panel
    instrument = page.locator("text=INSTRUMENT")
    if instrument.count() > 0 and instrument.first.is_visible():
        finding("PASS", "Panels", "Instrument panel visible")
    else:
        finding("P1", "Panels", "Instrument panel NOT visible")

    # Media Pool
    media_pool = page.locator("text=MEDIA POOL")
    if media_pool.count() > 0 and media_pool.first.is_visible():
        finding("PASS", "Panels", "Media Pool panel visible")
    else:
        finding("P1", "Panels", "Media Pool NOT visible")

    page.screenshot(path="/tmp/brutalwav-qa/04_panels_check.png", full_page=True)

    # === TEST 2: Transport controls ===
    print("\n=== TEST 2: Transport Controls ===")
    console_errors.clear()
    page_errors.clear()

    # Find play button
    play_btn = page.locator("button:has-text('\\u25b6')").first  # Unicode play triangle
    if not play_btn.is_visible():
        play_btn = page.locator("[aria-label*='play' i], [aria-label*='Play']").first
    if not play_btn.is_visible():
        # Try by position - buttons near transport
        all_buttons = page.locator("button")
        btn_count = all_buttons.count()
        print(f"  Total buttons: {btn_count}")
        for i in range(btn_count):
            b = all_buttons.nth(i)
            if b.is_visible():
                t = b.inner_text().strip()
                print(f"  Button {i}: '{t}' (repr: {repr(t)})")

    # Click play
    try:
        play_btn.click()
        page.wait_for_timeout(500)
        finding("PASS", "Transport", "Play button clickable")
    except Exception as e:
        finding("P1", "Transport", "Play button click failed", str(e))

    # Check position counter changes (should start moving if playing)
    position = page.locator("text=001").first
    if position.is_visible():
        finding("PASS", "Transport", "Position counter visible")
    else:
        finding("P2", "Transport", "Position counter not found")

    # Click stop
    stop_btn = page.locator("button:has-text('\\u25a0')").first  # Unicode stop square
    if not stop_btn.is_visible():
        stop_btn = page.locator("[aria-label*='stop' i], [aria-label*='Stop']").first
    try:
        stop_btn.click()
        page.wait_for_timeout(300)
        finding("PASS", "Transport", "Stop button clickable")
    except Exception as e:
        finding("P1", "Transport", "Stop button click failed", str(e))

    # BPM change
    bpm_input = page.locator("input").first
    if bpm_input.is_visible():
        bpm_input.triple_click()
        bpm_input.fill("140")
        bpm_input.press("Enter")
        page.wait_for_timeout(300)
        new_val = bpm_input.input_value()
        if new_val == "140":
            finding("PASS", "Transport", "BPM change works (120 -> 140)")
        else:
            finding("P1", "Transport", f"BPM change failed (expected 140, got {new_val})")
        # Reset
        bpm_input.triple_click()
        bpm_input.fill("120")
        bpm_input.press("Enter")
    else:
        finding("P1", "Transport", "BPM input not found for editing")

    # LOOP toggle
    loop_btn = page.locator("text=LOOP").first
    if loop_btn.is_visible():
        loop_btn.click()
        page.wait_for_timeout(200)
        finding("PASS", "Transport", "LOOP toggle clickable")
    else:
        finding("P2", "Transport", "LOOP button not found")

    # MET toggle
    met_btn = page.locator("text=MET").first
    if met_btn.is_visible():
        met_btn.click()
        page.wait_for_timeout(200)
        finding("PASS", "Transport", "MET toggle clickable")
    else:
        finding("P2", "Transport", "MET button not found")

    if page_errors:
        for e in page_errors:
            finding("P0", "Transport", "Page error during transport tests", e)

    page.screenshot(path="/tmp/brutalwav-qa/05_transport.png", full_page=True)

    # === TEST 3: Keyboard shortcuts ===
    print("\n=== TEST 3: Keyboard Shortcuts ===")
    console_errors.clear()
    page_errors.clear()

    # Space for play/stop
    page.keyboard.press("Space")
    page.wait_for_timeout(500)
    finding("PASS", "Shortcuts", "Space key pressed (play/stop)")

    page.keyboard.press("Space")
    page.wait_for_timeout(300)
    finding("PASS", "Shortcuts", "Space key pressed again (stop)")

    # Shift+? for shortcuts panel
    page.keyboard.press("Shift+?")
    page.wait_for_timeout(500)
    page.screenshot(path="/tmp/brutalwav-qa/06_shortcuts_panel.png", full_page=True)

    # Check if shortcuts panel appeared
    shortcuts_panel = page.locator("text=Shortcuts")
    if shortcuts_panel.count() > 0:
        finding("PASS", "Shortcuts", "Shortcuts panel opens with Shift+?")
        # Close it
        page.keyboard.press("Escape")
        page.wait_for_timeout(300)
    else:
        # Try the ? button instead
        help_btn = page.locator("button:has-text('?')")
        if help_btn.count() > 0 and help_btn.first.is_visible():
            help_btn.first.click()
            page.wait_for_timeout(500)
            page.screenshot(path="/tmp/brutalwav-qa/06b_help_click.png", full_page=True)
            finding("P2", "Shortcuts", "Shift+? may not work but ? button exists")
            page.keyboard.press("Escape")
            page.wait_for_timeout(300)
        else:
            finding("P2", "Shortcuts", "Shortcuts panel not found after Shift+?")

    if page_errors:
        for e in page_errors:
            finding("P0", "Shortcuts", "Page error during shortcut tests", e)

    # === TEST 4: Add a track and check panels ===
    print("\n=== TEST 4: Add Track ===")
    console_errors.clear()
    page_errors.clear()

    # Look for + button to add track
    add_btn = page.locator("text=+").first
    if not add_btn.is_visible():
        add_btn = page.locator("[aria-label*='add' i], [aria-label*='Add']").first

    # Actually check all buttons
    all_btns = page.locator("button")
    for i in range(all_btns.count()):
        b = all_btns.nth(i)
        if b.is_visible():
            t = b.inner_text().strip()
            if t == "+" or "add" in t.lower():
                print(f"  Found add button: '{t}'")
                add_btn = b
                break

    try:
        add_btn.click()
        page.wait_for_timeout(1000)
        page.screenshot(path="/tmp/brutalwav-qa/07_after_add_track.png", full_page=True)
        finding("PASS", "Tracks", "Add track button clicked")
    except Exception as e:
        finding("P1", "Tracks", "Could not click add track button", str(e))

    if page_errors:
        for e in page_errors:
            finding("P0", "Tracks", "Page error after adding track", e)

    # === TEST 5: Viewport at 1024px ===
    print("\n=== TEST 5: Viewport 1024px ===")
    page.set_viewport_size({"width": 1024, "height": 768})
    page.wait_for_timeout(500)
    page.screenshot(path="/tmp/brutalwav-qa/08_viewport_1024.png", full_page=True)

    # Check for horizontal overflow
    has_overflow = page.evaluate("""() => {
        return document.documentElement.scrollWidth > document.documentElement.clientWidth;
    }""")
    if has_overflow:
        scroll_w = page.evaluate("() => document.documentElement.scrollWidth")
        client_w = page.evaluate("() => document.documentElement.clientWidth")
        finding("P1", "Layout", f"Horizontal overflow at 1024px (scroll: {scroll_w}, client: {client_w})")
    else:
        finding("PASS", "Layout", "No horizontal overflow at 1024px viewport")

    # Reset viewport
    page.set_viewport_size({"width": 1280, "height": 800})
    page.wait_for_timeout(300)

    # === TEST 6: Focus management / Accessibility ===
    print("\n=== TEST 6: Accessibility ===")

    # Tab through controls
    page.keyboard.press("Tab")
    page.wait_for_timeout(200)
    focused = page.evaluate("() => document.activeElement?.tagName + '.' + document.activeElement?.className")
    print(f"  After Tab 1: focused = {focused}")

    page.keyboard.press("Tab")
    page.wait_for_timeout(200)
    focused2 = page.evaluate("() => document.activeElement?.tagName + '.' + document.activeElement?.className")
    print(f"  After Tab 2: focused = {focused2}")

    page.keyboard.press("Tab")
    page.wait_for_timeout(200)
    focused3 = page.evaluate("() => document.activeElement?.tagName + '.' + document.activeElement?.className")
    print(f"  After Tab 3: focused = {focused3}")

    # Check if focus rings are visible
    focus_ring_styles = page.evaluate("""() => {
        const el = document.activeElement;
        if (!el) return 'no active element';
        const style = window.getComputedStyle(el);
        return {
            outline: style.outline,
            outlineColor: style.outlineColor,
            outlineStyle: style.outlineStyle,
            outlineWidth: style.outlineWidth,
            boxShadow: style.boxShadow,
        };
    }""")
    print(f"  Focus styles: {focus_ring_styles}")

    if isinstance(focus_ring_styles, dict):
        has_focus_indicator = (
            focus_ring_styles.get("outlineStyle", "none") != "none" or
            focus_ring_styles.get("boxShadow", "none") != "none"
        )
        if has_focus_indicator:
            finding("PASS", "A11y", "Focus ring visible on active element")
        else:
            finding("P2", "A11y", "Focus ring may not be visible", str(focus_ring_styles))
    else:
        finding("P2", "A11y", "Could not check focus styles")

    page.screenshot(path="/tmp/brutalwav-qa/09_focus.png", full_page=True)

    # Check ARIA roles
    roles = page.evaluate("""() => {
        const els = document.querySelectorAll('[role]');
        return Array.from(els).map(e => ({
            role: e.getAttribute('role'),
            tag: e.tagName,
            label: e.getAttribute('aria-label') || '',
        }));
    }""")
    print(f"  Found {len(roles)} elements with ARIA roles")
    for r in roles[:10]:
        print(f"    {r['tag']} role={r['role']} label={r['label']}")

    if len(roles) > 0:
        finding("PASS", "A11y", f"Found {len(roles)} ARIA-annotated elements")
    else:
        finding("P2", "A11y", "No ARIA roles found in the DOM")

    # Check for aria-labels on buttons
    btns_without_label = page.evaluate("""() => {
        const buttons = document.querySelectorAll('button');
        const noLabel = [];
        for (const btn of buttons) {
            const text = btn.textContent?.trim();
            const label = btn.getAttribute('aria-label');
            if (!text && !label) {
                noLabel.push(btn.outerHTML.substring(0, 100));
            }
        }
        return noLabel;
    }""")
    if btns_without_label:
        finding("P2", "A11y", f"{len(btns_without_label)} buttons without text or aria-label", str(btns_without_label[:3]))
    else:
        finding("PASS", "A11y", "All buttons have text or aria-label")

    # === FINAL: Check for any accumulated errors ===
    print("\n=== Final Error Check ===")
    if page_errors:
        for e in page_errors:
            finding("P0", "Runtime", "Uncaught page error", e)

    if console_errors:
        for e in console_errors:
            finding("P1", "Runtime", "Console error", e)

    # Save results
    with open("/tmp/brutalwav-qa/qa_results.json", "w") as f:
        json.dump(FINDINGS, f, indent=2)

    browser.close()

# === REPORT ===
print("\n" + "=" * 60)
print("BRUTALWAV QA REPORT")
print("=" * 60)

p0 = [f for f in FINDINGS if f["severity"] == "P0"]
p1 = [f for f in FINDINGS if f["severity"] == "P1"]
p2 = [f for f in FINDINGS if f["severity"] == "P2"]
p3 = [f for f in FINDINGS if f["severity"] == "P3"]
passed = [f for f in FINDINGS if f["severity"] == "PASS"]

print(f"\nPASSED: {len(passed)}")
print(f"P0 (Critical): {len(p0)}")
print(f"P1 (Major): {len(p1)}")
print(f"P2 (Minor): {len(p2)}")
print(f"P3 (Cosmetic): {len(p3)}")

for sev, items in [("P0", p0), ("P1", p1), ("P2", p2), ("P3", p3)]:
    if items:
        print(f"\n--- {sev} Issues ---")
        for f in items:
            print(f"  [{f['category']}] {f['message']}")
            if f.get("detail"):
                print(f"    -> {f['detail'][:200]}")

print(f"\n--- PASSED ({len(passed)}) ---")
for f in passed:
    print(f"  [{f['category']}] {f['message']}")

