    focus_ring_styles = page.evaluate("""() => {
        const el = document.activeElement;
        if (!el) return 'no active element';
        const style = window.getComputedStyle(el);
        return {
            outline: style.outline,
            outlineColor: style.outlineColor,
            outlineStyle: style.outlineStyle,
            outlineWidth: style.outlineWidth,
            boxShadow: style.boxShadow,
        };
    }""")
    print(f"  Focus styles: {focus_ring_styles}")

    if isinstance(focus_ring_styles, dict):
        has_focus_indicator = (
            focus_ring_styles.get("outlineStyle", "none") != "none" or
            focus_ring_styles.get("boxShadow", "none") != "none"
        )
        if has_focus_indicator:
            finding("PASS", "A11y", "Focus ring visible on active element")
        else:
            finding("P2", "A11y", "Focus ring may not be visible", str(focus_ring_styles))
    else:
        finding("P2", "A11y", "Could not check focus styles")

    page.screenshot(path="/tmp/brutalwav-qa/09_focus.png", full_page=True)

    # Check ARIA roles
    roles = page.evaluate("""() => {
        const els = document.querySelectorAll('[role]');
        return Array.from(els).map(e => ({
            role: e.getAttribute('role'),
            tag: e.tagName,
            label: e.getAttribute('aria-label') || '',
        }));
    }""")
    print(f"  Found {len(roles)} elements with ARIA roles")
    for r in roles[:10]:
        print(f"    {r['tag']} role={r['role']} label={r['label']}")

    if len(roles) > 0:
        finding("PASS", "A11y", f"Found {len(roles)} ARIA-annotated elements")
    else:
        finding("P2", "A11y", "No ARIA roles found in the DOM")

    # Check for aria-labels on buttons
    btns_without_label = page.evaluate("""() => {
        const buttons = document.querySelectorAll('button');
        const noLabel = [];
        for (const btn of buttons) {
            const text = btn.textContent?.trim();
            const label = btn.getAttribute('aria-label');
            if (!text && !label) {
                noLabel.push(btn.outerHTML.substring(0, 100));
            }
        }
        return noLabel;
    }""")
    if btns_without_label:
        finding("P2", "A11y", f"{len(btns_without_label)} buttons without text or aria-label", str(btns_without_label[:3]))
    else:
        finding("PASS", "A11y", "All buttons have text or aria-label")

    # === FINAL: Check for any accumulated errors ===
    print("\n=== Final Error Check ===")
    if page_errors:
        for e in page_errors:
            finding("P0", "Runtime", "Uncaught page error", e)

    if console_errors:
        for e in console_errors:
            finding("P1", "Runtime", "Console error", e)

    # Save results
    with open("/tmp/brutalwav-qa/qa_results.json", "w") as f:
        json.dump(FINDINGS, f, indent=2)

    browser.close()

# === REPORT ===
print("\n" + "=" * 60)
print("BRUTALWAV QA REPORT")
print("=" * 60)

p0 = [f for f in FINDINGS if f["severity"] == "P0"]
p1 = [f for f in FINDINGS if f["severity"] == "P1"]
p2 = [f for f in FINDINGS if f["severity"] == "P2"]
p3 = [f for f in FINDINGS if f["severity"] == "P3"]
passed = [f for f in FINDINGS if f["severity"] == "PASS"]

print(f"\nPASSED: {len(passed)}")
print(f"P0 (Critical): {len(p0)}")
print(f"P1 (Major): {len(p1)}")
print(f"P2 (Minor): {len(p2)}")
print(f"P3 (Cosmetic): {len(p3)}")

for sev, items in [("P0", p0), ("P1", p1), ("P2", p2), ("P3", p3)]:
    if items:
        print(f"\n--- {sev} Issues ---")
        for f in items:
            print(f"  [{f['category']}] {f['message']}")
            if f.get("detail"):
                print(f"    -> {f['detail'][:200]}")

print(f"\n--- PASSED ({len(passed)}) ---")
for f in passed:
    print(f"  [{f['category']}] {f['message']}")

