6	import { MediaPoolPanel } from "./media-pool/MediaPoolPanel";
7	import { CommandRegistry } from "./keyboard/command-registry";
8	import { ShortcutMap } from "./keyboard/shortcut-map";
9	import { useKeyboardShortcuts } from "./keyboard/useKeyboardShortcuts";
10	import { useTransportShortcuts } from "./transport/useTransportShortcuts";
11	import { useSessionShortcuts } from "./session/useSessionShortcuts";
12	import { RecoveryDialog } from "./session/RecoveryDialog";
13	import { TransportProvider } from "@audio/transport-provider";
14	import { EffectsBridgeProvider } from "@audio/effects/EffectsBridgeProvider";
15	import { RoutingBridgeProvider } from "@audio/mixer/RoutingBridgeProvider";
16	import { useMediaPool } from "@audio/media-pool/use-media-pool";
17	import { sharedUndoManager } from "@state/undo/shared-undo-manager";
18	import { useSessionPersistence } from "@state/session/use-session-persistence";
19	import type { SessionStorage } from "@state/session/session-storage";
20	import { createDefaultSession } from "@state/session/session-schema";
21	import { hydrateStore } from "@state/session/use-session-persistence";
