26	function DawShellInner({
27	  sessionStorage,
28	}: {
29	  sessionStorage: SessionStorage;
30	}): React.JSX.Element {
31	  const registry = useMemo(() => new CommandRegistry(), []);
32	  const shortcuts = useMemo(() => new ShortcutMap(), []);
33	  const pool = useMediaPool();
34	  const undoManager = sharedUndoManager;
35	  const { saveNow, recoveryWarnings } = useSessionPersistence(sessionStorage);
36	  const [dismissed, setDismissed] = useState(false);
37	  const [shortcutsOpen, setShortcutsOpen] = useState(false);
38	  const [toastMessage, setToastMessage] = useState<string | null>(null);
39	  const toastCountRef = useRef(0);
40	  const showRecovery = !dismissed && recoveryWarnings.length > 0;
41	
42	  const stableSaveNow = useCallback(() => saveNow(), [saveNow]);
43	
44	  const showToast = useCallback((msg: string) => {
45	    toastCountRef.current += 1;
46	    setToastMessage(`${msg}#${String(toastCountRef.current)}`);
47	  }, []);
48	
49	  useTransportShortcuts(registry, shortcuts);
50	  useSessionShortcuts(
51	    registry,
52	    shortcuts,
53	    undoManager,
54	    stableSaveNow,
55	    showToast,
56	  );
57	
58	  useEffect(() => {
59	    registry.register({
60	      id: "app.shortcuts-legend",
61	      label: "Toggle Keyboard Shortcuts",
62	      execute: () => {
63	        setShortcutsOpen((prev) => !prev);
64	      },
65	    });
66	    shortcuts.bind({
67	      key: "?",
68	      shift: true,
69	      commandId: "app.shortcuts-legend",
70	    });
71	    return () => {
72	      registry.unregister("app.shortcuts-legend");
73	      shortcuts.unbind("app.shortcuts-legend");
74	    };
75	  }, [registry, shortcuts]);
76	
77	  useKeyboardShortcuts(registry, shortcuts);
78	
79	  return (
80	    <div
81	      data-testid="daw-shell"
82	      style={{
83	        display: "flex",
84	        flexDirection: "column",
85	        height: "100vh",
86	        backgroundColor: "var(--color-black)",
87	      }}
88	    >
89	      <Toolbar />
90	      <ErrorBoundary fallbackLabel="Panel crashed">
91	        <div
92	          style={{
93	            display: "flex",
94	            flexDirection: "column",
95	            flex: 1,
96	            overflow: "hidden",
97	          }}
98	        >
99	          <ArrangementPanel />
100	          <MixerPanel />
101	          <div style={{ display: "flex", overflow: "hidden" }}>
102	            <div style={{ flex: 1 }}>
103	              <InstrumentPanel />
104	            </div>
105	            <div style={{ flex: 1 }}>
106	              <MediaPoolPanel pool={pool} />
107	            </div>
108	          </div>
109	        </div>
110	      </ErrorBoundary>
111	      <KeyboardShortcutsPanel
112	        open={shortcutsOpen}
113	        onClose={() => {
114	          setShortcutsOpen(false);
115	        }}
116	      />
117	      <RecoveryDialog
118	        open={showRecovery}
119	        warnings={recoveryWarnings}
120	        onAccept={() => {
121	          setDismissed(true);
122	        }}
123	        onDiscard={() => {
124	          hydrateStore(createDefaultSession());
125	          setDismissed(true);
126	        }}
127	      />
128	      <ActionToast message={toastMessage} />
129	    </div>
130	  );
131	}
132	
133	export function DawShell({
134	  sessionStorage,
135	}: {
136	  sessionStorage: SessionStorage;
137	}): React.JSX.Element {
138	  return (
139	    <TransportProvider>
140	      <EffectsBridgeProvider>
141	        <RoutingBridgeProvider>
142	          <DawShellInner sessionStorage={sessionStorage} />
143	        </RoutingBridgeProvider>
144	      </EffectsBridgeProvider>
145	    </TransportProvider>
146	  );
147	}
