231	export class MoveClipCommand implements UndoCommand {
232	  readonly type = "move-clip";
233	
234	  private oldStartTime = 0;
235	  private oldTrackId = "";
236	
237	  constructor(
238	    private readonly clipId: string,
239	    private readonly newStartTime: number,
240	    private readonly newTrackId?: string,
241	  ) {}
242	
243	  execute(): void {
