269	// SplitClipCommand
270	// ---------------------------------------------------------------------------
271	
272	export class SplitClipCommand implements UndoCommand {
273	  readonly type = "split-clip";
274	
275	  private originalClip: ClipModel | undefined;
276	  private generatedRightId: string | undefined;
277	
278	  constructor(
279	    private readonly clipId: string,
280	    private readonly atTime: number,
281	  ) {}
282	
283	  rightClipId(): string | undefined {
284	    return this.generatedRightId;
285	  }
286	
287	  execute(): void {
288	    // Capture full original clip before split
289	    this.originalClip = getStore().clips[this.clipId];
290	    // Pass stored ID on redo to keep clip references deterministic
291	    this.generatedRightId = getStore().splitClip(
292	      this.clipId,
293	      this.atTime,
294	      this.generatedRightId,
295	    );
296	  }
297	
298	  undo(): void {
299	    if (this.originalClip === undefined) return;
300	
301	    // Remove the right clip created by split
302	    if (this.generatedRightId !== undefined) {
303	      getStore().removeClip(this.generatedRightId);
304	    }
305	
306	    // Restore original clip state (splitClip mutated the left clip in-place)
307	    useDawStore.setState((state) => ({
308	      clips: { ...state.clips, [this.clipId]: this.originalClip as ClipModel },
309	    }));
310	  }
311	
312	  serialize(): Record<string, unknown> {
313	    return {
314	      clipId: this.clipId,
315	      atTime: this.atTime,
316	      rightClipId: this.generatedRightId,
317	      originalClip: this.originalClip,
318	    };
319	  }
320	}
