21	  meterLevel: number;
22	  meterPeak: number;
23	  clipping: boolean;
24	  onVolumeChange: (trackId: string, volume: number) => void;
25	  onPanChange: (trackId: string, pan: number) => void;
26	  onMuteToggle: (trackId: string) => void;
27	  onSoloToggle: (trackId: string) => void;
28	};
29	
30	export function ChannelStrip({
31	  trackId,
32	  name,
33	  color,
34	  volume,
35	  pan,
36	  muted,
37	  solo,
38	  meterLevel,
39	  meterPeak,
