1	import { z } from "zod/v4";
2	import { trackSchema, clipSchema } from "@state/track/index";
3	import { effectsSectionSchema } from "@state/effects/index";
4	import { modulationSectionSchema } from "@state/synth/modulation-schema";
5	import { arpeggiatorSectionSchema } from "@state/arpeggiator/index";
6	import { automationSectionSchema } from "@state/automation/index";
7	
8	export const SESSION_VERSION = 1;
9	
10	export const metaSectionSchema = z.object({
11	  name: z.string(),
12	  createdAt: z.number(),
13	  updatedAt: z.number(),
14	});
15	
16	export const transportSectionSchema = z
17	  .object({
18	    bpm: z.number().min(1).max(999),
19	    loopEnabled: z.boolean(),
20	    loopStart: z.number().min(0),
21	    loopEnd: z.number().min(0),
22	  })
23	  .refine((t) => t.loopEnd >= t.loopStart, {
24	    message: "loopEnd must be >= loopStart",
25	  });
26	
27	export const mixerSectionSchema = z.object({
28	  masterVolume: z.number().min(0).max(2),
29	});
30	
31	export const sessionSchema = z.object({
32	  version: z.literal(SESSION_VERSION),
33	  meta: metaSectionSchema,
34	  transport: transportSectionSchema,
35	  tracks: z.array(trackSchema),
36	  clips: z.array(clipSchema),
37	  mixer: mixerSectionSchema,
38	  effects: effectsSectionSchema.optional(),
39	  modulation: modulationSectionSchema.optional(),
40	  arpeggiator: arpeggiatorSectionSchema.optional(),
41	  automation: automationSectionSchema.optional(),
42	});
43	
44	export type SessionSchema = z.infer<typeof sessionSchema>;
45	
46	export function createDefaultSession(): SessionSchema {
47	  const now = Date.now();
48	  return {
49	    version: SESSION_VERSION,
50	    meta: { name: "Untitled", createdAt: now, updatedAt: now },
51	    transport: { bpm: 120, loopEnabled: false, loopStart: 0, loopEnd: 0 },
52	    tracks: [],
53	    clips: [],
54	    mixer: { masterVolume: 1 },
55	  };
56	}
