"""QA: Test instrument panels (synth, drum machine, piano roll) by injecting tracks."""
from playwright.sync_api import sync_playwright
import json

FINDINGS = []

def finding(severity, category, msg, detail=""):
    FINDINGS.append({"severity": severity, "category": category, "message": msg, "detail": detail})
    print(f"[{severity}] {category}: {msg}")
    if detail:
        print(f"    Detail: {detail[:200]}")

with sync_playwright() as p:
    browser = p.chromium.launch(headless=True)
    context = browser.new_context(viewport={"width": 1280, "height": 800})
    page = context.new_page()

    page_errors = []
    console_errors = []
    page.on("pageerror", lambda err: page_errors.append(str(err)))
    page.on("console", lambda msg: console_errors.append(msg.text) if msg.type == "error" else None)

    # Navigate and start
    page.goto("http://localhost:5173/", wait_until="networkidle")
    page.click("button")
    page.wait_for_timeout(2000)

    # === Inject an instrument track via Zustand store ===
    print("=== Injecting instrument track ===")
    result = page.evaluate("""() => {
        // Access Zustand store - it's exposed on useDawStore
        // We need to find the store on the React fiber tree or window
        // Zustand stores with devtools can be accessed via window.__ZUSTAND_DEVTOOLS__
        // Otherwise we'll try to dispatch directly

        // Try to access via React internals
        const rootEl = document.getElementById('root');
        if (!rootEl || !rootEl._reactRootContainer) {
            // React 18+ uses createRoot - fiber is on the container
        }

        // The store is likely available on window or we can reach it through the module system
        // In dev mode with Vite, modules are available
        return 'need_alternative_approach';
    }""")

    # Try a different approach - use the Vite HMR module system
    result2 = page.evaluate("""() => {
        // Check if store is exposed somewhere
        const keys = Object.keys(window).filter(k => k.includes('store') || k.includes('zustand') || k.includes('daw'));
        return { windowKeys: keys.slice(0, 20), hasDevtools: !!window.__ZUSTAND_DEVTOOLS_STORES__ };
    }""")
    print(f"  Window check: {result2}")

    # The store won't be directly on window. Let me try to access it through React fiber
    result3 = page.evaluate("""() => {
        // Walk the React fiber tree to find the store
        const root = document.getElementById('root');
        let fiber = root?._reactRootContainer?._internalRoot?.current || root?.['__reactFiber$' + Object.keys(root).find(k => k.startsWith('__reactFiber$'))?.replace('__reactFiber$', '')];

        // Alternative: try to access the fiber from any rendered element
        const anyEl = root?.firstChild;
        if (anyEl) {
            const fiberKey = Object.keys(anyEl).find(k => k.startsWith('__reactFiber$'));
            if (fiberKey) {
                return { hasFiber: true, fiberKey };
            }
        }
        return { hasFiber: false, rootKeys: Object.keys(root || {}).slice(0, 10) };
    }""")
    print(f"  Fiber check: {result3}")

    # Most reliable approach: import the module directly via Vite's module graph
    try:
        result4 = page.evaluate("""async () => {
            try {
                const storeModule = await import('/src/state/store.ts');
                if (storeModule.useDawStore) {
                    const store = storeModule.useDawStore;
                    const state = store.getState();
                    return {
                        success: true,
                        trackCount: state.tracks.length,
                        hasAddTrack: typeof state.addTrack === 'function'
                    };
                }
                return { success: false, keys: Object.keys(storeModule) };
            } catch (e) {
                return { success: false, error: e.message };
            }
        }""")
        print(f"  Direct import: {result4}")
    except Exception as e:
        print(f"  Direct import failed: {e}")
        result4 = {"success": False}

    if result4.get("success"):
        # Add an instrument track
        add_result = page.evaluate("""async () => {
            const { useDawStore } = await import('/src/state/store.ts');
            const store = useDawStore;

            // Add instrument track
            store.getState().addTrack({
                id: 'qa-inst-1',
                name: 'QA Synth',
                type: 'instrument',
                color: '#00ff88',
                muted: false,
                solo: false,
                armed: false,
                soloIsolate: false,
                volume: 1.0,
                pan: 0,
                clipIds: [],
            });

            // Select it
            store.getState().selectTrack('qa-inst-1');

            const state = store.getState();
            return {
                trackCount: state.tracks.length,
                selectedIds: state.selectedTrackIds,
                trackNames: state.tracks.map(t => t.name)
            };
        }""")
        print(f"  Track added: {add_result}")

        page.wait_for_timeout(500)
        page.screenshot(path="/tmp/brutalwav-qa/10_instrument_track.png", full_page=True)

        # Check if synth editor appeared
        synth_editor = page.locator("[data-testid='instrument-panel']")
        if synth_editor.count() > 0:
            content = synth_editor.first.inner_text()
            if "INSTRUMENT" not in content or len(content) > 20:
                finding("PASS", "SynthEditor", f"Synth editor rendered for instrument track")
            else:
                finding("P2", "SynthEditor", "Instrument panel shows but may not have synth editor", content[:100])
        else:
            finding("P1", "SynthEditor", "Instrument panel not found after adding track")

        # Check for synth-specific elements (oscillator, filter, envelope, etc.)
        body = page.inner_text("body")
        synth_keywords = ["OSC", "FILTER", "ENVELOPE", "LFO", "osc", "filter", "envelope", "lfo",
                         "Sine", "Square", "Saw", "Triangle", "sine", "square", "saw",
                         "Cutoff", "Resonance", "Attack", "Decay", "Sustain", "Release",
                         "cutoff", "resonance", "attack", "decay", "sustain", "release"]
        found_keywords = [kw for kw in synth_keywords if kw in body]
        if found_keywords:
            finding("PASS", "SynthEditor", f"Synth UI elements found: {', '.join(found_keywords[:10])}")
        else:
            finding("P2", "SynthEditor", "No synth-specific keywords found in body")
            print(f"  Body text (first 1000): {body[:1000]}")

        # Check for virtual keyboard
        keyboard_el = page.locator("[data-testid*='keyboard'], [class*='keyboard'], [class*='piano']")
        if keyboard_el.count() > 0:
            finding("PASS", "VirtualKeyboard", "Virtual keyboard element found")
        else:
            # Check for keyboard-like elements (buttons/divs representing keys)
            keys = page.locator("[data-note], [class*='key'], [class*='Key']")
            if keys.count() > 0:
                finding("PASS", "VirtualKeyboard", f"Found {keys.count()} key elements")
            else:
                finding("P2", "VirtualKeyboard", "No virtual keyboard elements found")

        # Check mixer with track
        mixer = page.locator("[data-testid='mixer-panel']")
        if mixer.count() > 0:
            mixer_text = mixer.first.inner_text()
            if "QA Synth" in mixer_text:
                finding("PASS", "Mixer", "Track channel strip visible in mixer")
            else:
                finding("P2", "Mixer", "Track not visible in mixer", mixer_text[:200])

        page.screenshot(path="/tmp/brutalwav-qa/11_synth_detail.png", full_page=True)

        # Now add an audio track too
        page.evaluate("""async () => {
            const { useDawStore } = await import('/src/state/store.ts');
            useDawStore.getState().addTrack({
                id: 'qa-audio-1',
                name: 'QA Audio',
                type: 'audio',
                color: '#ff8800',
                muted: false,
                solo: false,
                armed: false,
                soloIsolate: false,
                volume: 1.0,
                pan: 0,
                clipIds: [],
            });
        }""")
        page.wait_for_timeout(300)
        page.screenshot(path="/tmp/brutalwav-qa/12_two_tracks.png", full_page=True)

        # Check arrangement with tracks
        arrangement = page.locator("[role='application']")
        if arrangement.count() > 0:
            finding("PASS", "Arrangement", "Arrangement canvas found with tracks")
        else:
            finding("P2", "Arrangement", "Arrangement canvas not found")

    else:
        finding("P1", "StoreAccess", "Could not access Zustand store to inject test tracks")

    # === Check for drum machine panel ===
    print("\n=== Checking Drum Machine ===")
    drum_panel = page.locator("text=DRUM, text=drum, [data-testid*='drum']")
    if drum_panel.count() > 0:
        finding("PASS", "DrumMachine", "Drum machine panel found")
    else:
        # The drum machine might not be in the current layout
        # Check if the component exists but isn't rendered
        finding("P3", "DrumMachine", "Drum machine panel not visible in current layout (may require specific track type)")

    # === Check piano roll ===
    print("\n=== Checking Piano Roll ===")
    piano_roll = page.locator("[data-testid*='piano-roll'], [class*='pianoRoll'], text=Piano Roll")
    if piano_roll.count() > 0:
        finding("PASS", "PianoRoll", "Piano roll found")
    else:
        finding("P3", "PianoRoll", "Piano roll not visible in current layout (may require MIDI clip selection)")

    # === Test at 1024px with tracks ===
    print("\n=== Viewport 1024px with tracks ===")
    page.set_viewport_size({"width": 1024, "height": 768})
    page.wait_for_timeout(500)
    page.screenshot(path="/tmp/brutalwav-qa/13_1024_with_tracks.png", full_page=True)

    has_overflow = page.evaluate("""() => {
        return document.documentElement.scrollWidth > document.documentElement.clientWidth;
    }""")
    if has_overflow:
        scroll_w = page.evaluate("() => document.documentElement.scrollWidth")
        client_w = page.evaluate("() => document.documentElement.clientWidth")
        finding("P1", "Layout", f"Horizontal overflow at 1024px with tracks (scroll: {scroll_w}, client: {client_w})")
    else:
        finding("PASS", "Layout", "No overflow at 1024px with tracks")

    # === Final error check ===
    if page_errors:
        for e in page_errors:
            finding("P0", "Runtime", "Uncaught page error", e)
    else:
        finding("PASS", "Runtime", "No uncaught page errors during instrument tests")

    if console_errors:
        for e in console_errors:
            finding("P1", "Console", "Console error during instrument tests", e)
    else:
        finding("PASS", "Console", "No console errors during instrument tests")

    with open("/tmp/brutalwav-qa/instrument_results.json", "w") as f:
        json.dump(FINDINGS, f, indent=2)

    browser.close()

# Report
print("\n" + "=" * 60)
print("INSTRUMENT PANEL QA REPORT")
print("=" * 60)

for sev in ["P0", "P1", "P2", "P3"]:
    items = [f for f in FINDINGS if f["severity"] == sev]
    if items:
        print(f"\n--- {sev} Issues ---")
        for f in items:
            print(f"  [{f['category']}] {f['message']}")

passed = [f for f in FINDINGS if f["severity"] == "PASS"]
print(f"\n--- PASSED ({len(passed)}) ---")
for f in passed:
    print(f"  [{f['category']}] {f['message']}")

