"""QA: Focus ring visibility and virtual keyboard testing."""
from playwright.sync_api import sync_playwright
import json

FINDINGS = []

def finding(severity, category, msg, detail=""):
    FINDINGS.append({"severity": severity, "category": category, "message": msg, "detail": detail})
    print(f"[{severity}] {category}: {msg}")
    if detail:
        print(f"    Detail: {detail[:200]}")

with sync_playwright() as p:
    browser = p.chromium.launch(headless=True)
    context = browser.new_context(viewport={"width": 1280, "height": 800})
    page = context.new_page()

    page_errors = []
    page.on("pageerror", lambda err: page_errors.append(str(err)))

    page.goto("http://localhost:5173/", wait_until="networkidle")
    page.click("button")
    page.wait_for_timeout(2000)

    # Add instrument track
    page.evaluate("""async () => {
        const { useDawStore } = await import('/src/state/store.ts');
        useDawStore.getState().addTrack({
            id: 'qa-inst-1', name: 'QA Synth', type: 'instrument',
            color: '#00ff88', muted: false, solo: false, armed: false,
            soloIsolate: false, volume: 1.0, pan: 0, clipIds: [],
        });
        useDawStore.getState().setSelectedTrackIds(['qa-inst-1']);
    }""")
    page.wait_for_timeout(500)

    # === TEST: Focus ring on global.css :focus-visible ===
    print("=== Focus Ring Test ===")

    # Check global.css :focus-visible rule
    focus_rule = page.evaluate("""() => {
        for (const sheet of document.styleSheets) {
            try {
                for (const rule of sheet.cssRules) {
                    if (rule.selectorText && rule.selectorText.includes('focus-visible')) {
                        return { selector: rule.selectorText, cssText: rule.cssText.substring(0, 200) };
                    }
                }
            } catch (e) {
                // cross-origin sheet
            }
        }
        return null;
    }""")
    print(f"  Focus-visible CSS rule: {focus_rule}")
    if focus_rule:
        finding("PASS", "FocusRing", "Global :focus-visible CSS rule found", str(focus_rule))
    else:
        finding("P2", "FocusRing", "No :focus-visible CSS rule found in stylesheets")

    # Tab to a button and check focus-visible state
    # First click somewhere neutral
    page.click("[data-testid='daw-shell']")
    page.wait_for_timeout(100)

    # Use keyboard to trigger focus-visible (Tab key triggers focus-visible)
    page.keyboard.press("Tab")
    page.wait_for_timeout(200)

    focus_info = page.evaluate("""() => {
        const el = document.activeElement;
        if (!el || el === document.body) return { tag: 'body', noFocus: true };
        const style = window.getComputedStyle(el);
        // Check pseudo :focus-visible
        const matches = el.matches(':focus-visible');
        return {
            tag: el.tagName,
            text: el.textContent?.substring(0, 50),
            focusVisible: matches,
            outline: style.outline,
            outlineStyle: style.outlineStyle,
            outlineWidth: style.outlineWidth,
            outlineColor: style.outlineColor,
            boxShadow: style.boxShadow,
        };
    }""")
    print(f"  After Tab: {focus_info}")

    if focus_info.get("focusVisible"):
        outline_visible = (
            focus_info.get("outlineStyle", "none") != "none" and
            focus_info.get("outlineWidth", "0px") != "0px"
        ) or focus_info.get("boxShadow", "none") != "none"
        if outline_visible:
            finding("PASS", "FocusRing", "Focus ring visible when Tab navigating",
                   f"outline: {focus_info.get('outline')}, boxShadow: {focus_info.get('boxShadow')}")
        else:
            finding("P2", "FocusRing", "Element has :focus-visible but no visible outline/shadow",
                   str(focus_info))
    else:
        finding("P2", "FocusRing", "Tab-focused element doesn't match :focus-visible", str(focus_info))

    # Tab more to check multiple elements
    for i in range(5):
        page.keyboard.press("Tab")
        page.wait_for_timeout(100)

    page.screenshot(path="/tmp/brutalwav-qa/14_focus_test.png", full_page=True)

    # === TEST: Virtual keyboard interaction ===
    print("\n=== Virtual Keyboard Test ===")

    keyboard_el = page.locator("[data-testid*='keyboard'], [class*='keyboard'], [class*='piano']")
    kbd_count = keyboard_el.count()
    print(f"  Virtual keyboard elements: {kbd_count}")

    if kbd_count > 0:
        # Try clicking on keyboard keys
        keys = page.locator("[data-testid*='keyboard'] button, [class*='keyboard'] button, [class*='key']")
        key_count = keys.count()
        print(f"  Key elements: {key_count}")

        if key_count > 0:
            # Click a few keys
            for i in range(min(3, key_count)):
                k = keys.nth(i)
                if k.is_visible():
                    try:
                        k.click()
                        page.wait_for_timeout(100)
                    except:
                        pass
            finding("PASS", "VirtualKeyboard", f"Found {key_count} clickable keys")
        else:
            # Check if keyboard is canvas-based
            canvas = page.locator("[class*='keyboard'] canvas, [data-testid*='keyboard'] canvas")
            if canvas.count() > 0:
                finding("PASS", "VirtualKeyboard", "Canvas-based virtual keyboard found")
            else:
                # Check for div-based keys
                div_keys = keyboard_el.first.locator("div")
                div_count = div_keys.count()
                print(f"  Div elements in keyboard: {div_count}")
                if div_count > 5:
                    # Likely div-based keyboard
                    finding("PASS", "VirtualKeyboard", f"Virtual keyboard has {div_count} div elements (likely key divs)")
                    # Try clicking on keyboard area
                    bbox = keyboard_el.first.bounding_box()
                    if bbox:
                        # Click in the middle of keyboard
                        page.mouse.click(bbox['x'] + bbox['width'] / 2, bbox['y'] + bbox['height'] / 2)
                        page.wait_for_timeout(200)
                        finding("PASS", "VirtualKeyboard", "Clicked on virtual keyboard area")
                else:
                    finding("P2", "VirtualKeyboard", "Keyboard element found but no clickable keys")
    else:
        finding("P2", "VirtualKeyboard", "No virtual keyboard elements found")

    page.screenshot(path="/tmp/brutalwav-qa/15_keyboard_test.png", full_page=True)

    # === TEST: Synth controls interaction ===
    print("\n=== Synth Controls Test ===")

    # Try changing oscillator type
    osc_select = page.locator("select").first
    if osc_select.is_visible():
        current = osc_select.input_value()
        print(f"  Current osc type: {current}")
        osc_select.select_option("square")
        page.wait_for_timeout(200)
        new_val = osc_select.input_value()
        if new_val == "square":
            finding("PASS", "SynthControls", "Oscillator type change works (saw -> square)")
        else:
            finding("P2", "SynthControls", f"Oscillator type change may have failed (got: {new_val})")
        # Reset
        osc_select.select_option(current)
    else:
        finding("P2", "SynthControls", "Oscillator select not found")

    # Try adjusting a range slider
    sliders = page.locator("input[type='range']")
    slider_count = sliders.count()
    print(f"  Range sliders: {slider_count}")
    if slider_count > 0:
        finding("PASS", "SynthControls", f"Found {slider_count} parameter sliders")
    else:
        finding("P2", "SynthControls", "No range sliders found in synth editor")

    # Check Mute/Solo buttons
    m_btn = page.locator("button:has-text('M')").first
    s_btn = page.locator("button:has-text('S')").first
    if m_btn.is_visible():
        m_btn.click()
        page.wait_for_timeout(200)
        finding("PASS", "Mixer", "Mute button clickable")
        m_btn.click()  # unmute
    if s_btn.is_visible():
        s_btn.click()
        page.wait_for_timeout(200)
        finding("PASS", "Mixer", "Solo button clickable")
        s_btn.click()  # unsolo

    page.screenshot(path="/tmp/brutalwav-qa/16_synth_controls.png", full_page=True)

    # === Final errors ===
    if page_errors:
        for e in page_errors:
            finding("P0", "Runtime", "Page error during focus/keyboard tests", e)
    else:
        finding("PASS", "Runtime", "No page errors during focus/keyboard tests")

    with open("/tmp/brutalwav-qa/focus_keyboard_results.json", "w") as f:
        json.dump(FINDINGS, f, indent=2)

    browser.close()

# Report
print("\n" + "=" * 60)
print("FOCUS & KEYBOARD QA REPORT")
print("=" * 60)

